class Type(Enum):
    """
    Signal category. EPS_BEAT/EPS_MISS: actual EPS vs analyst estimate. REVENUE_BEAT/REVENUE_MISS: actual revenue vs estimate. MARGIN_EXPANSION/MARGIN_CONTRACTION: any of gross/operating/net margin moved year-over-year by ≥100bps. GUIDANCE_RAISED/GUIDANCE_LOWERED/GUIDANCE_REAFFIRMED/GUIDANCE_INITIATED: forward-looking guidance change reported in the filing. SEGMENT_OUTPERFORMANCE/SEGMENT_UNDERPERFORMANCE: best- or worst-performing reportable segment by organic revenue growth. NON_GAAP_DIVERGENCE: an adjusted/non-GAAP figure differs materially from its GAAP counterpart on the same period. BACKLOG_SURGE/BACKLOG_DECLINE: backlog or remaining performance obligations moved year-over-year by ≥20%. REVENUE_INCREASE/STRONG_REVENUE_INCREASE and DECLINE variants: tiered year-over-year revenue change (≥10% / ≥20% magnitude). NET_INCOME_INCREASE/STRONG_NET_INCOME_INCREASE and DECLINE variants: tiered year-over-year net income change (≥15% / ≥30%). EPS_INCREASE/STRONG_EPS_INCREASE and DECLINE variants: tiered year-over-year EPS change (≥15% / ≥30%); independent from net income because share buybacks can amplify EPS movement. CAPEX_INCREASE/STRONG_CAPEX_INCREASE and DECLINE variants: tiered year-over-year capital expenditure change in spending magnitude (≥15% / ≥30%).
    """

    eps_beat = 'EPS_BEAT'
    eps_miss = 'EPS_MISS'
    revenue_beat = 'REVENUE_BEAT'
